//    fee           = default 800 uqbtc, gas_limit 300000 (dApp may override)
//    primary case  : proposalId 42, option YES(1), sequence 7, accountNumber 100
//    abstain case  : proposalId 1,  option ABSTAIN(2), sequence 0, accountNumber 5
//
//  See QBTCSignDirectCosignByteEqualityTests for how the gate consumes these.
//

